%% Evaluate simulation times study study of geometrically exact beam models
% Requires the data generated by the corresponding simulation script.
%
% Maximilian Herrmann
% Chair of Automatic Control
% TUM School of Engineering and Design
% Technical University of Munich
%

%% Preparation

clear
close all

% Disable warnings for extra legend entries
warning('off', 'MATLAB:legend:IgnoringExtraEntries');


%% Script Settings

SAVE_RESULTS = 1;

PLOT_SUBFOLDER = 'evaluations';

PLOT_FOLDER = fullfile(getRootFolder, "results", "plots");


%% Load results

% Path to results folder
RESULTS_DIR = fullfile(getRootFolder, "results", "runs");

% Subfolder with data
SIM_SUBFOLDER = '260718_1733_simResults_simTimes';

% Load simCase struct
disp('Loading simulation results file...')
resultsPath = fullfile(RESULTS_DIR, SIM_SUBFOLDER);
results = load( fullfile( resultsPath, 'simTimeStudyResults.mat') );

beamPars = results.beamPars;
h = results.h;
nSeg = results.nSeg;

simError     = results.simError;
simTimeTotal = results.simTimeTotal;
modelNames   = [results.beamModels.modelName];
saveDirCase  = results.saveDirCase;

% Start diary to document results and computations
if SAVE_RESULTS
    diary(fullfile(resultsPath, 'evaluations_and_comparisons.log'));
end

%% Permute integrators

permuteVec   = [1, 2, 4, 3, 5];
simError     = simError(:,:,:,permuteVec);
simTimeTotal = simTimeTotal (:,:,:,permuteVec);
saveDirCase  = saveDirCase(:,:,permuteVec);

modelNames = ["Abs SR", "Rel SR Broyden", "Rel SR Recursive", "Rel KH Broyden", "Rel KH Recursive"];


%% General Plot settings

% Colors and Line styles for the individual integrators
plotColors = lines(4);
plotColors = plotColors(2:end, :);
plotLines  = ["-o", "-*", "-square"];
plotMarkers = ["+", "o", "square"];
plotMarkerEdgeColors = {"black", "black", "black"};

figHandles = {};


%% Metadata / Info about the parameters

% Info for first dimension / Young's modulus
dimInfo(1).legendStrings = compose("Mat=%d", 1:length(beamPars));
dimInfo(1).xAxisLabel = "Material";
dimInfo(1).xValues = 1:length(beamPars);
dimInfo(1).quantNameLong = "Material";
dimInfo(1).quantNameShort = "Mat";

% Info for 2nd dimension / time step
dimInfo(2).legendStrings = compose("h=%.2E", h);
dimInfo(2).xAxisLabel = "time step $h$ / s";
dimInfo(2).xValues = h;
dimInfo(2).quantNameLong = "Time Step $h$";
dimInfo(2).quantNameShort = "h";

% Info for 3rd dimension / nr. of segments
dimInfo(3).legendStrings = compose("nSeg=%d", nSeg);
dimInfo(3).xAxisLabel = "$n^{-1}$";
dimInfo(3).xValues = 1./nSeg;
dimInfo(3).quantNameLong = "Nr. of Segments";
dimInfo(3).quantNameShort = "nSeg";

% Info for 4th dimension / integrator model
% (will not be used as x axis values)
dimInfo(4).legendStrings = modelNames;
dimInfo(4).xAxisLabel = "";
dimInfo(4).xValues = 1:length(modelNames);
dimInfo(4).quantNameLong = "";
dimInfo(4).quantNameShort = "ints.";


%% Computation Time

[convTime_simTimes, convSpace_simTimes] = estimateConvRates(simTimeTotal, beamPars, h, nSeg, modelNames);

% Surf plot with separate plots in E
opts = struct( ...
    "figureName",       "Int Time / h & nSeg", ...
    "figureTitle",      "Total Integration Time over $h$ and nSeg", ...
    "axisLabel",        "total int. time / s" ...
    );

figHandles{end+1} = plotQuantitySurf(simTimeTotal, beamPars, h, nSeg, modelNames, opts);

% Separate 2D plots
figInfo = struct( ...
    "quantNameShort", "Int Time", ...
    "quantNameLong",  "Total Integration Time", ......
    "yAxisLabel",     "total int. time / s" ...
    );

figHandles{end+1} = plotQuantity2d(simTimeTotal, dimInfo, figInfo, convTime_simTimes, convSpace_simTimes);
figHandles{end+1} = plotQuantity2d(simTimeTotal, dimInfo, figInfo, [], []);


%% Iterations

%[convTime_simTimes, convSpace_simTimes] = estimateConvRates(simTimeTotal, mat, h, nSeg, modelNames);

% Surf plot with separate plots in E
opts = struct( ...
    "figureName",       "Mean Iter / h & nSeg", ...
    "figureTitle",      "Mean Iteration Count over $h$ and nSeg", ...
    "axisLabel",        "Mean Iteration Count" ...
    );

figHandles{end+1} = plotQuantitySurf(results.simIterationsAvg, beamPars, h, nSeg, modelNames, opts);

% Separate 2D plots
figInfo = struct( ...
    "quantNameShort", "Mean Iter", ...
    "quantNameLong",  "Mean Iteration Count", ......
    "yAxisLabel",     "Mean Iteration Count" ...
    );

figHandles{end+1} = plotQuantity2d(results.simIterationsAvg, dimInfo, figInfo, [], []);


%% Compute Minimal Time Step Data

% Get minimum time step and other data
% Go through the time step dimension and get index of first non-nan value
convMinTimeStepIndex = nan(length(nSeg), length(modelNames), length(beamPars));
convMinTimeStepValue = nan(length(nSeg), length(modelNames), length(beamPars));
minSimTime           = nan(length(nSeg), length(modelNames), length(beamPars));
errorMinSimTime      = nan(length(nSeg), length(modelNames), length(beamPars));
commonErrorLevel    = nan(2, length(beamPars));
simTimesMinMaxError = nan(2, length(modelNames),length(beamPars));

for iMdl = 1:length(modelNames)
    for iMat = 1:length(beamPars)
        for iSeg = 1:length(nSeg)
            firstIndex = find(~isnan(simTimeTotal(iMat,:,iSeg,iMdl)), 1);
            if ~isempty(firstIndex)

                convMinTimeStepIndex(iSeg,iMdl,iMat) = firstIndex;
                convMinTimeStepValue(iSeg,iMdl,iMat) = h(firstIndex);
                minSimTime(iSeg,iMdl,iMat)           = simTimeTotal(iMat,firstIndex, iSeg, iMdl);
                errorMinSimTime(iSeg,iMdl,iMat)      = simError(iMat,firstIndex, iSeg, iMdl);
            end
        end
    end
end

for iMat = 1:length(beamPars)

    % Get common error levels of all models at min and max nSeg
    commonErrorLevel(1,iMat) = min(errorMinSimTime(1,  :,iMat));
    commonErrorLevel(2,iMat) = max(errorMinSimTime(end,:,iMat));

    % Compute simulation times at these common error levels by
    % interpolation
    % Note: Use exp and log in the interpolation to get more accurate value
    % for the loglog plot
    % https://www.mathworks.com/matlabcentral/answers/501548-how-to-find-data-values-that-falls-on-line-connecting-loglog-plot-in-matlab
    for iMdl = 1:length(modelNames)
        nanVals = isnan(errorMinSimTime(:,iMdl,iMat));
        simTimesMinMaxError(:,iMdl, iMat) = exp(interp1( ...
            errorMinSimTime(~nanVals,iMdl,iMat), log(minSimTime(~nanVals,iMdl,iMat)), commonErrorLevel(:,iMat), ...
            'spline',nan...
            ));
    end

    % Print results
    fprintf('Min. time step for convergence (decimal), Mat=%d:\n', iMat);
    disp(array2table( ...
        convMinTimeStepValue(:,:,iMat), ...
        'RowNames', arrayfun(@(a) sprintf("nSeg = %d", a), nSeg), ...
        'VariableNames', modelNames ...
        ));

    fprintf('Min. time step for convergence (log2 / 2^X), Mat=%d:\n', iMat);
    disp(array2table( ...
        log2(convMinTimeStepValue(:,:,iMat)), ...
        'RowNames', arrayfun(@(a) sprintf("nSeg = %d", a), nSeg), ...
        'VariableNames', modelNames ...
        ));

    fprintf('Min. simulation time for given nSeg, Mat=%d:\n', iMat);
    disp(array2table( ...
        minSimTime(:,:,iMat), ...
        'RowNames', arrayfun(@(a) sprintf("nSeg = %d", a), nSeg), ...
        'VariableNames', modelNames ...
        ));

    fprintf('Factors min. computation time absKin SR / relKin KH (Broyden or Recursive) for given nSeg, Mat=%d:\n', iMat);
    disp(array2table( ...
        minSimTime(:,1,iMat)./min([minSimTime(:,4,iMat),minSimTime(:,5,iMat)], [], 2), ...
        'RowNames', arrayfun(@(a) sprintf("nSeg = %d", a), nSeg) ...
        ));

    fprintf('Error at minimum simulation time for given nSeg, Mat=%d:\n', iMat);
    disp(array2table( ...
        errorMinSimTime(:,:,iMat), ...
        'RowNames', arrayfun(@(a) sprintf("nSeg = %d", a), nSeg), ...
        'VariableNames', modelNames ...
        ));

    fprintf('Simulation times for given error level, Mat=%d:\n', iMat);
    disp( ...
        array2table(simTimesMinMaxError(:,:,iMat), ...
        'VariableNames',  modelNames, ...
        'RowNames', arrayfun(@(a) sprintf("e_rel = %d", a), commonErrorLevel(:,iMat)) ) ...
        );

    fprintf('Factors computation time absKin SR / relKin KH (Broyden or Recursive) for given error level, Mat=%d:\n', iMat);
    disp(array2table( ...
        simTimesMinMaxError(:,1,iMat)./min([simTimesMinMaxError(:,4,iMat),simTimesMinMaxError(:,5,iMat)], [], 2), ...
        'RowNames', arrayfun(@(a) sprintf("e_rel = %d", a), commonErrorLevel(:,iMat))  ...
        ));

end


%% Plot results

