%% Comparison Plots Simulation results

SIMULATION_COMPARISON = 1;

% Index of nSeg, at which to compare simulation results
nSegIndexComp = 2;
tEnd = 0.3; % Longer simulation time

% To generate plots:
% Set LOAD_MDLS to 0 to simulate the compared models and SAVE_MDLS to 1 to
% save the simulation data.
% If the simulations have been performed and saved once, set LOAD_MDLS to 1
% to directly load the saved data.

LOAD_MDLS = 1;
SAVE_MDLS = 1;

if SIMULATION_COMPARISON
    for iMat = 1:length(beamPars)

        filePath_compModel_Ref = fullfile( ...
            resultsPath, sprintf("beamMdl_simComparison_mdlRef_Mat=%d_nSeg=%d.mat", iMat, nSeg(nSegIndexComp)) ...
            );
        filePath_compModel_Abs = fullfile( ...
            resultsPath, sprintf("beamMdl_simComparison_mdlAbs_Mat=%d_nSeg=%d.mat", iMat, nSeg(nSegIndexComp)) ...
            );
        filePath_compModel_Rel = fullfile( ...
            resultsPath, sprintf("beamMdl_simComparison_mdlRelKH_Mat=%d_nSeg=%d.mat", iMat, nSeg(nSegIndexComp)) ...
            );

        if LOAD_MDLS
            % Load already simulated models from file
            mdlFileRef   = load(filePath_compModel_Ref);
            mdlFileAbsSR = load(filePath_compModel_Abs);
            mdlFileRelKH = load(filePath_compModel_Rel);

            mdlRef = mdlFileRef.obj;
            mdlAbs = mdlFileAbsSR.obj;
            mdlRelKH = mdlFileRelKH.obj;
        else
            % Load models (without simulation data) and simulate

            % Reference Simulation
            mdlFileRef = load( ...
                fullfile(resultsPath, sprintf("beamMdlRef_Mat_%d.mat", iMat) ) ...
                );

            mdlRef = mdlFileRef.obj;
            mdlRef.simPars.tEnd = tEnd;
            mdlRef.simulateModel();
            mdlRef.plotSimResults("hPlot", 2^-10);

            if SAVE_MDLS
                mdlRef.saveObject(filePath_compModel_Ref);
            end

            % Coarse simulations
            mdlFileAbsSR = load( ...
                fullfile( ...
                saveDirCase(iMat, convMinTimeStepIndex(nSegIndexComp, 1, iMat), nSegIndexComp), ...
                strcat("beamMdl ", results.beamModels(1).modelName, ".mat") )...
                );
            mdlAbs = mdlFileAbsSR.obj;
            mdlAbs.simPars.tEnd = tEnd;
            mdlAbs.simulateModel("accurateTiming",true);
            mdlAbs.plotSimResults("hPlot", 2^-10);

            if SAVE_MDLS
                mdlAbs.saveObject(filePath_compModel_Abs);
            end


            mdlFileRelKH = load( ...
                fullfile( ...
                saveDirCase(iMat, convMinTimeStepIndex(nSegIndexComp, 4, iMat), nSegIndexComp), ...
                strcat("beamMdl ", results.beamModels(3).modelName, ".mat") )...
                );
            mdlRelKH = mdlFileRelKH.obj;
            mdlRelKH.simPars.tEnd = tEnd;
            mdlRelKH.simulateModel("accurateTiming",true);
            mdlRelKH.plotSimResults("hPlot", 2^-10);
            if SAVE_MDLS
                mdlRelKH.saveObject(filePath_compModel_Rel);
            end
        end


        %% Comparison Plots
        lineStylesComp = ["-", "--", "-."];
        yLabels = ["$x$ in m", "$y$ in m", "$z$ in m"];

        pdfWidth_comp = 450; % Page width in pt
        pdfAspectRatio_comp = 3.6;

        %%% Tip position
        fh = figure('Name',sprintf('Comparison Tip Position, Mat %d', iMat));
        tl = tiledlayout(fh, 1, 3);

        for iAxis = 1:3
            ax = nexttile;
            hold on;

            plot( ...
                mdlRef.simRes.simData.tout, ...
                squeeze(mdlRef.simRes.simData.x(iAxis,end,:)), ...
                lineStylesComp(1), ...
                'Color', lineColors(1, :), 'MarkerSize', markerSize, ...
