                'LineWidth', 1, ...
                'DisplayName', "Abs SR");

            plot( ...
                mdlRelKH.simRes.simData.tout, ...
                squeeze(mdlRelKH.simRes.simData.eta(iAxis+3,end,:)), ...
                lineStylesComp(3), ...
                'Color', lineColors(4, :), 'MarkerSize', markerSize, ...
