                'DisplayName', "Rel KH");

            ax.TickLabelInterpreter = "latex";
            xlabel('$t$ in s', 'Interpreter', 'latex');
            ylabel(yLabels(iAxis), 'Interpreter','latex');

            if iAxis == 1
                legend('Interpreter','latex','Location','southeast');
            end
            grid on;
            box on;
        end
        tl.Padding = "tight";
        tl.TileSpacing = "tight";

        formatAndSaveFigureFixedWidth(fh, pdfWidth_comp, pdfAspectRatio_comp, PLOT_FOLDER);
    end
end


%% Save Plots

figHandlesVec = [figHandles{:}];

if SAVE_RESULTS
    disp('Saving Plots...')

    saveDirPlots = fullfile( resultsPath, PLOT_SUBFOLDER );

    % Create output folder
    if ~isfolder( saveDirPlots )
        mkdir( saveDirPlots );
    end

    % Case Plots
    for iPlot = 1:length(figHandlesVec)

        % Replace '/' in figure names
        figName = replace( figHandlesVec(iPlot).Name, '/', '--');

        filePath = fullfile( resultsPath, PLOT_SUBFOLDER, figName );

        % Save as figure
        savefig(figHandlesVec(iPlot), sprintf('%s.fig', filePath));

        % Save as jpeg
        exportgraphics(figHandlesVec(iPlot), sprintf('%s.jpeg', filePath));
    end
end


%% End script
diary off
disp('Finished.');
